// Sections 4–5: Actors & Stakeholders Catalog + Functional Requirements per actor.
import { h1, h2, p, bullet, table, reqBlock, callout, spacer } from "./helpers.mjs";

export const actorsCatalog = () => [
  h1("4. Actors and Stakeholders"),
  p("An actor is anyone (or anything) that interacts with the system. Each actor below has a dedicated set of requirements in Section 5, identified by the code shown. One real person may hold several roles (e.g. a lecturer who is also a Head of Department); the system's role model allows this."),
  table(
    ["Code", "Actor", "Who they are"],
    [
      ["AP", "Prospective Applicant", "Anyone applying for admission — WASSCE school leaver, mature applicant, international applicant, postgraduate or distance-learning candidate"],
      ["ST", "Student", "An enrolled undergraduate, postgraduate or distance student"],
      ["LEC", "Lecturer", "Teaching staff assigned to courses: delivers content, assesses and grades"],
      ["HOD", "Head of Department", "Academic manager of a department: assigns courses, first approver of grades and registrations"],
      ["DEA", "Dean of School", "Academic head of a school: oversees departments, second approver in academic workflows"],
      ["ADM", "Admissions Officer", "Runs admission cycles: reviews applications, prepares decisions, issues offers"],
      ["REG", "Registrar / Academic Affairs Officer", "Custodian of academic records, calendars, policies and final academic sign-offs"],
      ["EXO", "Examinations Officer", "Manages examinations, results processing, publication and transcripts"],
      ["FIN", "Finance Officer (Bursar's Office)", "Sets fees, bills students, reconciles payments, manages arrears"],
      ["ACC", "Accommodation Manager", "Manages hostels, rooms, booking windows and allocations"],
      ["LIB", "Librarian", "Manages the catalogue, memberships, borrowing and fines"],
      ["HRO", "Human Resources Officer", "Maintains staff records, appointments and leave administration"],
      ["GSO", "Graduate School Officer / Thesis Supervisor", "Administers postgraduate study: supervision, thesis milestones, examinations"],
      ["CNS", "Counsellor / Student Affairs Officer", "Supports student welfare; receives early-warning flags and manages cases"],
      ["QAO", "Quality Assurance Officer", "Monitors academic quality: course evaluations, audits, accreditation evidence"],
      ["MGT", "University Management (VC / Pro-VC / Council)", "Consumes dashboards and reports; grants high-level approvals"],
      ["ALU", "Alumnus / Alumna", "A graduate who maintains a relationship with the university"],
      ["SYS", "IT / System Administrator", "Configures and operates the platform: users, roles, integrations, backups"],
      ["PAR", "Parent / Sponsor (optional persona)", "A fee payer granted read-only visibility of bills and payments for a student"],
    ],
    { widths: [8, 28, 64] }
  ),
  spacer(),
  callout("HOW TO READ SECTION 5", "Every requirement is written in plain English as “The [actor] shall be able to …” and carries a unique ID (e.g. AP-04) so it can be referenced in design, testing and acceptance. Cross-cutting requirements that apply to everyone (login, notifications, accessibility) are stated once in 5.20."),
];

